#include <stdio.h>
#include <string.h>
#include <stdint.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        char S[105];
        scanf("%d %d %s", &N, &K, S);
        int64_t ans = 0;
        for (int l = 0; l < N; ++l) {
            for (int r = l; r < N; ++r) {
                int mism = 0;
                int half = (r - l) / 2;
                for (int i = 0; i <= half; ++i) {
                    if (S[l + i] != S[r - i]) {
                        ++mism;
                        if (mism > K) break;
                    }
                }
                if (mism <= K) ans += (int64_t)(r - l + 1);
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

