import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        K = int(next(it))
        S = next(it)
        ans = 0
        for l in range(N):
            for r in range(l, N):
                mism = 0
                half = (r - l) // 2
                for i in range(half + 1):
                    if S[l + i] != S[r - i]:
                        mism += 1
                        if mism > K:
                            break
                if mism <= K:
                    ans += (r - l + 1)
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

